10	fn replacement_for(template: &[char]) -> Vec<char> {
11	    let mut replacement = "vice versa".chars().collect::<Vec<_>>();
12	
13	    let mut has_upper = false;
14	    let mut has_lower = false;
15	    let mut first_alpha_upper = None;
16	
17	    for ch in template.iter().copied() {
18	        if !ch.is_alphabetic() {
19	            continue;
20	        }
21	
22	        has_upper |= ch.is_uppercase();
23	        has_lower |= ch.is_lowercase();
24	
25	        if first_alpha_upper.is_none() {
26	            first_alpha_upper = Some(ch.is_uppercase());
27	        }
28	    }
29	
30	    if has_upper && !has_lower {
31	        for ch in replacement.iter_mut() {
32	            if ch.is_alphabetic() {
33	                *ch = ch.to_ascii_uppercase();
34	            }
35	        }
36	
37	        return replacement;
38	    }
39	
40	    if !has_upper {
41	        return replacement;
42	    }
43	
44	    if first_alpha_upper.unwrap_or(false) {
45	        let mut capitalized_first = false;
46	
47	        for ch in replacement.iter_mut() {
48	            if !ch.is_alphabetic() {
49	                continue;
50	            }
51	
52	            if !capitalized_first {
53	                *ch = ch.to_ascii_uppercase();
54	                capitalized_first = true;
55	            } else {
56	                *ch = ch.to_ascii_lowercase();
57	            }
58	        }
59	
60	        return replacement;
61	    }
62	
63	    for ch in replacement.iter_mut() {
64	        if ch.is_alphabetic() {
65	            *ch = ch.to_ascii_lowercase();
66	        }
67	    }
68	
69	    replacement
70	}
