38	impl<D> PronounVerbAgreement<D>
39	where
40	    D: Dictionary,
41	{
42	    pub fn new(dict: D) -> Self {
43	        // TODO: allowing "you" leads to false positives:
44	        // "8 years to give you rewards", "all I can do is give you examples"
45	        let non_3p_sing_pres_pron_with_3p_sing_pres_verb = SequenceExpr::default()
46	            .then_kind_both_but_not(
47	                (
48	                    TokenKind::is_personal_pronoun,
49	                    TokenKind::is_subject_pronoun,
50	                ),
51	                TokenKind::is_third_person_singular_pronoun,
52	            )
53	            .t_ws()
54	            // NOTE: allowing verbs that are also nouns leads to false positives:
55	            // "Are they colors or colours?"
56	            // "8 years to give you rewards"
57	            // "all I can do is give you examples"
58	            .then_verb_third_person_singular_present_form();
