60	        // NOTE: But excluding them causes many more false positives:
61	        // boxes, does, drops, flies, gets, goes, likes, site, wakes
62	        // .then_kind_where(|k| k.is_verb_third_person_singular_present_form() && !k.is_plural_noun());
63	
64	        let third_person_sing_pres_pron = |t: &Token, _: &[char]| {
65	            t.kind.is_subject_pronoun()
66	                && !t.kind.is_object_pronoun()
67	                && t.kind.is_personal_pronoun()
68	                && t.kind.is_third_person_singular_pronoun()
69	                && !t.kind.is_plural_pronoun()
70	        };
71	
72	        let verb_lemma = |t: &Token, src: &[char]| {
73	            t.kind.is_verb_lemma()
74	                && !t.kind.is_verb_third_person_singular_present_form()
75	                && !t.kind.is_verb_simple_past_form() // eg. not "put"
76	                && !t.kind.is_adverb() // eg. not "even"
77	                && !t.kind.is_conjunction() // "and"
78	                && (!t.kind.is_auxiliary_verb() // "I go"≠"he goes" but "I can"="he can"
