84	            expr: FirstMatchOf::new(vec![
85	                // One Expr for the "I walks" type:
86	                Box::new(non_3p_sing_pres_pron_with_3p_sing_pres_verb),
87	                // Two Expr's for the "he walk" type:
88	                Box::new(
89	                    SequenceExpr::with(third_person_sing_pres_pron)
