use crate::patterns::{InflectionOfBe, ModalVerb, WordSet};
use crate::{Token, TokenStringExt};

pub struct VerseVerb {
    expr: FirstMatchOf,
}

impl Default for VerseVerb {
    fn default() -> Self {
        let subject = |tok: &Token, _src: &[char]| {
            (tok.kind.is_nominal() || tok.kind.is_oov())
                && !tok.kind.is_object_pronoun()
                && !tok.kind.is_possessive_nominal()
        };

        let optional_adverb = SequenceExpr::default().then_adverb().t_ws();
        let auxiliary_or_modal = FirstMatchOf::new(vec![
            Box::new(InflectionOfBe::default()),
            Box::new(ModalVerb::default()),
            Box::new(WordSet::new(&[
                "do", "does", "did", "don't", "doesn't", "didn't", "dont", "doesnt", "didnt",
                "have", "has", "had", "haven't", "hasn't", "hadn't", "havent", "hasnt",
                "hadnt",
            ])),
        ]);

        let after_subject_or_aux = SequenceExpr::with(subject)
            .t_ws()
            .then_optional(optional_adverb)
            .then_optional(SequenceExpr::with(auxiliary_or_modal).t_ws())
            .then_optional(SequenceExpr::default().then_adverb().t_ws())
            .then_word_set(&["verse", "verses", "versed", "versing"]);

        let after_to = SequenceExpr::aco("to")
            .t_ws()
            .then_word_set(&["verse", "verses", "versed", "versing"]);

        Self {
            expr: FirstMatchOf::new(vec![Box::new(after_subject_or_aux), Box::new(after_to)]),
        }
    }
}

impl ExprLinter for VerseVerb {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        &self.expr
    }

    fn match_to_lint(&self, toks: &[Token], src: &[char]) -> Option<Lint> {
        let verse_tok = toks.iter().find(|tok| {
            tok.span.get_content(src).eq_any_ignore_ascii_case_str(&[
                "verse", "verses", "versed", "versing",
            ])
        })?;
        let verse_chars = verse_tok.span.get_content(src);
        let replacement = if verse_chars.eq_ignore_ascii_case_str("versing") {
            "facing"
        } else if verse_chars.eq_ignore_ascii_case_str("versed") {
            "faced"
        } else if verse_chars.eq_ignore_ascii_case_str("verses") {
            "faces"
        } else {
            "face"
        };

        Some(Lint {
            span: verse_tok.span,
            lint_kind: LintKind::WordChoice,
            suggestions: vec![
                Suggestion::replace_with_match_case_str(replacement, verse_chars),
                Suggestion::replace_with_match_case_str("play against", verse_chars),
                Suggestion::replace_with_match_case_str("compete against", verse_chars),
                Suggestion::replace_with_match_case_str("challenge", verse_chars),
            ],
            message: "When using `verse` as a verb related to `versus`, prefer `face`, `play against`, `compete against`, or `challenge`.".to_owned(),
            priority: 31,
