use harper_core::Document;
use harper_core::linting::{Linter, LintGroup};
use harper_core::spell::FstDictionary;
use harper_core::Dialect;

fn main() {
    for text in [
        "You can verse the bot online.",
        "The player is versing a PC.",
        "I have versed both duos and trios.",
        "Team A verses every other team twice.",
        "The poem has three verses.",
        "She is well versed in Rust.",
    ] {
        let doc = Document::new_plain_english_curated(text);
        let mut group = LintGroup::new_curated(FstDictionary::curated(), Dialect::American);
        let lints = group.lint(&doc);
        println!("TEXT: {text}");
        for lint in lints {
            println!("span {:?} text={} kind={:?} msg={} suggs={:?}", lint.span, lint.span.get_content_string(doc.get_source()), lint.lint_kind, lint.message, lint.suggestions);
        }
    }
}

